SELECT SUM(amount) AS total_spent_2023
FROM financial_entries
WHERE year = 2023;

SELECT COUNT(ledger_id) AS total_active_ledger_accounts
FROM ledger_accounts
WHERE is_active = 1;

SELECT ledger_name
FROM ledger_accounts
WHERE is_active = 1;

SELECT cost_center_name
FROM cost_centers
WHERE is_active = 1;

SELECT entry_id, amount
FROM financial_entries
WHERE is_approved = 1;
